import{_ as t,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o as d,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"User Rate Limits","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Safety/user-rate-limits.md","filePath":"ta/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),r={name:"ta/Safety/user-rate-limits.md"};function o(p,e,n,u,c,m){return d(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="user-rate-limits" tabindex="-1">User Rate Limits <a class="header-anchor" href="#user-rate-limits" aria-label="Permalink to &quot;User Rate Limits&quot;">​</a></h1><p>User rate limits homepage-ல் இருந்து regular users அல்லது visitors எவ்வளவு அடிக்கடி files upload செய்யலாம் என்பதை கட்டுப்படுத்தும். public upload pages abuse ஆகாமல் இருக்க உதவும்.</p><p>இந்த feature homepage uploads-ஐ மட்டுமே பாதிக்கும். Admin uploads மற்றும் API Tokens மூலம் செய்யப்பட்ட uploads user rate limits-ல் கட்டுப்படாது.</p><h2 id="எங்கு-configure-செய்வது" tabindex="-1">எங்கு Configure செய்வது <a class="header-anchor" href="#எங்கு-configure-செய்வது" aria-label="Permalink to &quot;எங்கு Configure செய்வது&quot;">​</a></h2><p>admin panel திறந்து செல்லவும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+t+'" alt="User rate limit settings" loading="lazy"></p><h2 id="rate-limits-enable-செய்தல்" tabindex="-1">Rate Limits Enable செய்தல் <a class="header-anchor" href="#rate-limits-enable-செய்தல்" aria-label="Permalink to &quot;Rate Limits Enable செய்தல்&quot;">​</a></h2><p><code>Enable Rate Limits</code> on செய்த பிறகு ImgBed uploader IP address அடிப்படையில் recent uploads track செய்யும்.</p><p>Default values:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>upload records எவ்வளவு பின்வரை எண்ணப்படும்.</td></tr><tr><td>Max file count</td><td>20</td><td>detection window-ல் அனுமதிக்கப்படும் அதிகபட்ச files.</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>ஒரு file-க்கான maximum size.</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>detection window-ல் maximum total upload size.</td></tr></tbody></table><p>உதாரணமாக 1.5 hour window, 20 files, file ஒன்றுக்கு 20 MB, total 200 MB என்றால் same IP-இல் இருந்து எந்த configured limit மீறினாலும் uploads blocked ஆகும்.</p><h2 id="file-types-exclude-செய்தல்" tabindex="-1">File Types Exclude செய்தல் <a class="header-anchor" href="#file-types-exclude-செய்தல்" aria-label="Permalink to &quot;File Types Exclude செய்தல்&quot;">​</a></h2><p><code>Excluded upload file types</code> regular users அல்லது visitors selected file categories upload செய்வதைத் தடுக்கிறது.</p><p>Available categories:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif போன்ற image files</td></tr><tr><td>Videos</td><td>mp4, webm, mov போன்ற video files</td></tr><tr><td>Audio</td><td>mp3, flac, wav போன்ற audio files</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx போன்ற document files</td></tr><tr><td>Other</td><td>மேலுள்ள categories-க்கு வெளியான files, உதா. zip, rar, exe, apk</td></tr></tbody></table><p>default-ஆக type selected இருக்காது; அதாவது அது allowed.</p><p>ஒரு type-ஐ click செய்தால் அது highlighted ஆகும்; அதாவது அந்த type blocked.</p><p><code>Other</code> selected என்றால் zip அல்லது rar upload செய்யும் visitors blocked ஆகி இந்த file type supported இல்லை என்று சொல்லப்படும்.</p><h2 id="block-messages" tabindex="-1">Block Messages <a class="header-anchor" href="#block-messages" aria-label="Permalink to &quot;Block Messages&quot;">​</a></h2><p>limit trigger ஆகும்போது users-க்கு பொருந்தும் message தெரியும்:</p><p><img src="'+a+'" alt="Too frequent upload message" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Message Meaning</th></tr></thead><tbody><tr><td>Single file too large</td><td>file பெரியது; upload-க்கு முன் compress செய்ய வேண்டும்.</td></tr><tr><td>File type blocked</td><td>இந்த file type supported இல்லை. அதை remove செய்து மீண்டும் முயற்சி செய்யவும்.</td></tr><tr><td>Uploads too frequent</td><td>recent uploads மிக frequent; retry time காட்டப்படும்.</td></tr><tr><td>Total size too high</td><td>recent total upload size அதிகம்; retry time காட்டப்படும்.</td></tr></tbody></table><h2 id="எப்போது-enable-செய்வது" tabindex="-1">எப்போது Enable செய்வது <a class="header-anchor" href="#எப்போது-enable-செய்வது" aria-label="Permalink to &quot;எப்போது Enable செய்வது&quot;">​</a></h2><p>உங்கள் upload homepage public accessible என்றால் user rate limits enable செய்யவும்.</p><p>பொதுவான காரணங்கள்:</p><ul><li>scripted bulk uploads பற்றி கவலை இருந்தால்.</li><li>visitor uploads பெரியதாக இருக்காமல் limit செய்ய விரும்பினால்.</li><li>regular users images மட்டும் upload செய்ய வேண்டும்; archives/installers வேண்டாம் என்றால்.</li><li>public upload திறந்தே இருக்க வேண்டும், ஆனால் resource usage கட்டுப்பட வேண்டும் என்றால்.</li></ul><p>site உங்களுக்காக மட்டும், அல்லது administrators மட்டும் upload செய்கிறார்கள் என்றால் disabled விடலாம்.</p>',28)])])}const f=i(r,[["render",o]]);export{g as __pageData,f as default};
